ALGORITHM HybridKeyExchange
// This algorithm demonstrates distributing a symmetric session key
// using asymmetric encryption (RSA)

INPUT: recipient_public_key (PU_bob), sender_private_key (PR_alice)
OUTPUT: shared_session_key (K) - known to both parties

// ================================================
// PHASE 1: KEY GENERATION (Alice's side)
// ================================================

PROCEDURE GenerateSessionKey()
  // Generate a random symmetric session key for this session
  K ← GenerateRandomBits(128)  // 128-bit key for AES-128
  RETURN K
END PROCEDURE

// ================================================
// PHASE 2: ENCRYPTION (Alice's side)
// ================================================

PROCEDURE EncryptSessionKey(K, PU_bob)
  // Alice encrypts the session key K with Bob's public key
  // This ensures only Bob can decrypt it with his private key

  ciphertext ← RSA_Encrypt(plaintext=K, public_key=PU_bob)
  RETURN ciphertext
END PROCEDURE

// ================================================
// PHASE 3: TRANSMISSION
// ================================================

// Alice sends ciphertext to Bob over the insecure network
// Eve can intercept the ciphertext but cannot decrypt it
// without Bob's private key

// ================================================
// PHASE 4: DECRYPTION (Bob's side)
// ================================================

PROCEDURE DecryptSessionKey(ciphertext, PR_bob)
  // Bob decrypts the ciphertext using his private key
  // This recovers the original session key K

  K ← RSA_Decrypt(ciphertext=ciphertext, private_key=PR_bob)
  RETURN K
END PROCEDURE

// ================================================
// PHASE 5: SECURE COMMUNICATION (Both parties)
// ================================================

PROCEDURE EncryptMessage(message, K)
  // Use symmetric encryption (AES) with the shared session key
  encrypted_message ← AES_Encrypt(plaintext=message, key=K)
  RETURN encrypted_message
END PROCEDURE

PROCEDURE DecryptMessage(encrypted_message, K)
  // Use symmetric decryption to recover the original message
  message ← AES_Decrypt(ciphertext=encrypted_message, key=K)
  RETURN message
END PROCEDURE

// ================================================
// MAIN EXECUTION FLOW
// ================================================

BEGIN
  // Step 1: Bob generates RSA key pair
  (PU_bob, PR_bob) ← RSA_KeyGen(key_size=2048)

  // Step 2: Alice generates a random symmetric session key
  K ← GenerateSessionKey()

  // Step 3: Alice encrypts session key with Bob's public key
  ciphertext ← EncryptSessionKey(K, PU_bob)

  // Step 4: Alice sends ciphertext to Bob
  TRANSMIT(ciphertext)

  // Step 5: Bob receives and decrypts to get session key
  K_recovered ← DecryptSessionKey(ciphertext, PR_bob)

  // Verify both keys match
  IF K == K_recovered THEN
    PRINT "Session key established successfully!"
    // Now use K for symmetric encryption/decryption
  ELSE
    PRINT "Key exchange failed!"
  END IF
END

/*
 * Hybrid Key Distribution: RSA for Key Exchange + AES for Bulk Data
 * This C program demonstrates the hybrid cryptosystem approach:
 * - RSA (asymmetric): Encrypt AES session key with recipient's public key
 * - AES (symmetric): Use session key for efficient bulk encryption
 * 
 * Compile: gcc -o hybrid_encrypt hybrid_encrypt.c -lssl -lcrypto
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <openssl/rsa.h>
#include <openssl/pem.h>
#include <openssl/err.h>
#include <openssl/aes.h>
#include <openssl/rand.h>

#define RSA_KEY_SIZE 2048
#define AES_KEY_SIZE 256
#define AES_IV_SIZE 16

/* Function to generate RSA key pair */
int generate_rsa_keypair(RSA **public_key, RSA **private_key) {
    RSA *rsa = NULL;
    BIGNUM *bn = NULL;

    // Create RSA structure
    rsa = RSA_new();
    bn = BN_new();

    // Set public exponent 65537
    if (!BN_set_word(bn, RSA_F4)) {
        fprintf(stderr, "Error setting BIGNUM\n");
        return -1;
    }

    // Generate RSA key pair
    if (!RSA_generate_key_ex(rsa, RSA_KEY_SIZE, bn, NULL)) {
        fprintf(stderr, "Error generating RSA key\n");
        return -1;
    }

    *public_key = rsa;
    *private_key = RSA_new();

    // Copy the private key
    if (!RSA_copy(*private_key, rsa)) {
        fprintf(stderr, "Error copying RSA key\n");
        return -1;
    }

    BN_free(bn);
    return 0;
}

/* Generate random AES session key */
unsigned char* generate_session_key(int key_size) {
    unsigned char *key = (unsigned char *)malloc(key_size);
    if (!key) return NULL;

    if (!RAND_bytes(key, key_size)) {
        fprintf(stderr, "Error generating random key\n");
        free(key);
        return NULL;
    }
    return key;
}

/* Encrypt session key using RSA public key */
int encrypt_session_key(RSA *public_key, 
                        unsigned char *session_key, 
                        int key_len,
                        unsigned char **encrypted_key, 
                        int *encrypted_len) {
    *encrypted_len = RSA_size(public_key);
    *encrypted_key = (unsigned char *)malloc(*encrypted_len);

    if (!*encrypted_key) {
        fprintf(stderr, "Memory allocation error\n");
        return -1;
    }

    // Use OAEP padding with SHA-256
    int result = RSA_public_encrypt(key_len, 
                                     session_key, 
                                     *encrypted_key, 
                                     public_key, 
                                     RSA_PKCS1_OAEP_PADDING);

    if (result == -1) {
        fprintf(stderr, "RSA encryption error: %s\n", ERR_error_string(ERR_get_error(), NULL));
        free(*encrypted_key);
        *encrypted_key = NULL;
        return -1;
    }

    *encrypted_len = result;
    return 0;
}

/* Decrypt session key using RSA private key */
int decrypt_session_key(RSA *private_key, 
                        unsigned char *encrypted_key, 
                        int encrypted_len,
                        unsigned char **session_key) {
    int rsa_size = RSA_size(private_key);
    *session_key = (unsigned char *)malloc(rsa_size);

    if (!*session_key) {
        fprintf(stderr, "Memory allocation error\n");
        return -1;
    }

    int result = RSA_private_decrypt(encrypted_len, 
                                      encrypted_key, 
                                      *session_key, 
                                      private_key, 
                                      RSA_PKCS1_OAEP_PADDING);

    if (result == -1) {
        fprintf(stderr, "RSA decryption error: %s\n", ERR_error_string(ERR_get_error(), NULL));
        free(*session_key);
        *session_key = NULL;
        return -1;
    }

    return result; // Returns actual key length
}

/* AES encryption with CBC mode */
int aes_encrypt(unsigned char *plaintext, int plaintext_len,
                unsigned char *key, unsigned char **ciphertext, unsigned char **iv) {
    *iv = (unsigned char *)malloc(AES_IV_SIZE);
    if (!*iv) return -1;

    // Generate random IV
    if (!RAND_bytes(*iv, AES_IV_SIZE)) {
        free(*iv);
        return -1;
    }

    // Calculate padding length
    int pad_len = AES_BLOCK_SIZE - (plaintext_len % AES_BLOCK_SIZE);
    int ciphertext_len = plaintext_len + pad_len;

    *ciphertext = (unsigned char *)malloc(ciphertext_len);
    if (!*ciphertext) {
        free(*iv);
        return -1;
    }

    AES_KEY aes_key;
    AES_set_encrypt_key(key, AES_KEY_SIZE, &aes_key);

    // Encrypt (with padding)
    AES_cbc_encrypt(plaintext, *ciphertext, plaintext_len, 
                    &aes_key, *iv, AES_ENCRYPT);

    return ciphertext_len;
}

/* AES decryption with CBC mode */
int aes_decrypt(unsigned char *ciphertext, int ciphertext_len,
                unsigned char *key, unsigned char *iv,
                unsigned char **plaintext) {
    *plaintext = (unsigned char *)malloc(ciphertext_len);
    if (!*plaintext) return -1;

    AES_KEY aes_key;
    AES_set_decrypt_key(key, AES_KEY_SIZE, &aes_key);

    // Decrypt (with unpadding)
    AES_cbc_encrypt(ciphertext, *plaintext, ciphertext_len,
                    &aes_key, iv, AES_DECRYPT);

    return ciphertext_len;
}

void print_hex(const char *label, unsigned char *data, int len) {
    printf("%s: ", label);
    for (int i = 0; i < len && i < 32; i++) {
        printf("%02x", data[i]);
    }
    if (len > 32) printf("...");
    printf("\n");
}

int main() {
    printf("============================================================\n");
    printf("  HYBRID KEY DISTRIBUTION DEMONSTRATION (C + OpenSSL)\n");
    printf("============================================================\n\n");

    RSA *bob_public_key = NULL;
    RSA *bob_private_key = NULL;
    unsigned char *session_key = NULL;
    unsigned char *encrypted_session_key = NULL;
    unsigned char *recovered_session_key = NULL;
    int encrypted_len, recovered_len;

    // Step 1: Bob generates RSA key pair
    printf("[Step 1] Bob generates RSA-2048 key pair\n");
    if (generate_rsa_keypair(&bob_public_key, &bob_private_key) != 0) {
        fprintf(stderr, "Key generation failed\n");
        return 1;
    }
    printf("  -> RSA key pair generated successfully\n\n");

    // Step 2: Alice generates random AES-256 session key
    printf("[Step 2] Alice generates random AES-256 session key\n");
    session_key = generate_session_key(AES_KEY_SIZE / 8);
    print_hex("  Session Key", session_key, AES_KEY_SIZE / 8);

    // Step 3: Alice encrypts session key with Bob's public key
    printf("\n[Step 3] Alice encrypts session key with RSA-OAEP\n");
    if (encrypt_session_key(bob_public_key, session_key, AES_KEY_SIZE / 8,
                            &encrypted_session_key, &encrypted_len) != 0) {
        fprintf(stderr, "Session key encryption failed\n");
        return 1;
    }
    print_hex("  Encrypted Key", encrypted_session_key, encrypted_len);

    // Step 4: Transmission (simulated)
    printf("\n[Step 4] Encrypted key transmitted to Bob\n");
    printf("  -> (In real scenario: sent over insecure network)\n");

    // Step 5: Bob decrypts to recover session key
    printf("\n[Step 5] Bob decrypts with his RSA private key\n");
    if (decrypt_session_key(bob_private_key, encrypted_session_key, encrypted_len,
                           &recovered_session_key) == -1) {
        fprintf(stderr, "Session key decryption failed\n");
        return 1;
    }
    print_hex("  Recovered Key", recovered_session_key, AES_KEY_SIZE / 8);

    // Verification
    printf("\n[Verification]\n");
    if (memcmp(session_key, recovered_session_key, AES_KEY_SIZE / 8) == 0) {
        printf("  ✓ Session key established successfully!\n");
    } else {
        printf("  ✗ Key exchange failed!\n");
        return 1;
    }

    // Step 6: Secure communication with AES
    printf("\n[Step 6] Secure communication using AES-256-CBC\n");
    const char *message = "Hello Bob! Secure message encrypted with session key.";
    unsigned char *ciphertext = NULL, *iv = NULL;
    unsigned char *decrypted = NULL;

    int cipher_len = aes_encrypt((unsigned char *)message, strlen(message),
                                  session_key, &ciphertext, &iv);

    printf("  Original: \"%s\"\n", message);
    print_hex("  Encrypted", ciphertext, cipher_len);

    int plain_len = aes_decrypt(ciphertext, cipher_len, recovered_session_key, iv, &decrypted);
    printf("  Decrypted: \"%s\"\n", decrypted);

    // Cleanup
    RSA_free(bob_public_key);
    RSA_free(bob_private_key);
    free(session_key);
    free(encrypted_session_key);
    free(recovered_session_key);
    free(ciphertext);
    free(iv);
    free(decrypted);

    printf("\n============================================================\n");
    printf("  KEY DISTRIBUTION COMPLETE\n");
    printf("============================================================\n");

    return 0;
}
